{"npsn":"50300404","name":"SD KATHOLIK BOKOS","address":"Oepoli","village":"Netemnanu Utara","status":"Swasta","jenjang":"SD","district":"Amfoang Timur","regencyBpsCode":"5301","regencyName":"Kabupaten Kupang","provinceName":"Nusa Tenggara Timur","school_id":"2d0e9ee3-c9f7-41b8-9c07-ad8efc61e6d9","user_id":"734368f5-f844-4111-9a85-baaf95aad803"},
{"npsn":"50306565","name":"SMP SAN DANIEL OEPOLI","address":"Jln.gereja Oepoli","village":"Netemnanu Utara","status":"Swasta","jenjang":"SMP","district":"Amfoang Timur","regencyBpsCode":"5301","regencyName":"Kabupaten Kupang","provinceName":"Nusa Tenggara Timur","school_id":"b268a299-cec9-46bf-93a3-0e5f779abe47","user_id":"7e162b60-0dda-4989-ac53-9e77447323d7"},
{"npsn":"50300406","name":"UPTD SD INPRES KIFU KEC. AMFOANG TIMUR","address":"Kifu","village":"Kifu","status":"Negeri","jenjang":"SD","district":"Amfoang Timur","regencyBpsCode":"5301","regencyName":"Kabupaten Kupang","provinceName":"Nusa Tenggara Timur","school_id":"73d5c55a-cb5b-4240-a70a-be5ac1911b4d","user_id":"ef0bcd4b-43be-4d0f-8ebe-f2afd1736bb8"},
{"npsn":"69726921","name":"UPTD SD NEGERI 2 TATAUM KEC. AMFOANG TIMUR","address":"Tataum","village":"Netemnanu Selatan","status":"Negeri","jenjang":"SD","district":"Amfoang Timur","regencyBpsCode":"5301","regencyName":"Kabupaten Kupang","provinceName":"Nusa Tenggara Timur","school_id":"82ff5cdc-d989-4892-b78e-18d8310eb7be","user_id":"ba226259-ab77-4de2-9d1c-05487997695c"}
]'::json;
BEGIN
    -- 1. Insert schools
    INSERT INTO public.schools (id, name, npsn, location, accreditation, regency_id)
    SELECT 
        (x.school_id)::uuid, 
        x.name, 
        x.npsn, 
        concat_ws(', ', nullif(x.address, ''), nullif(x.village, ''), nullif(x.district, ''), nullif(x."regencyName", ''), x."provinceName"),
        'C',
        r.id
    FROM json_to_recordset(v_data) AS x(
        school_id text, name text, npsn text, address text, village text, district text, "regencyName" text, "regencyBpsCode" text, "provinceName" text
    )
    JOIN public.regencies r ON r.code = x."regencyBpsCode"
    WHERE NOT EXISTS (SELECT 1 FROM public.schools s WHERE s.npsn = x.npsn);

    -- 2. Insert auth.users
    INSERT INTO auth.users (
        instance_id, id, aud, role, email, encrypted_password, 
        email_confirmed_at, recovery_sent_at, last_sign_in_at, 
        raw_app_meta_data, raw_user_meta_data, created_at, updated_at, 
        confirmation_token, email_change, email_change_token_new, recovery_token
    )
    SELECT 
        '00000000-0000-0000-0000-000000000000'::uuid, 
        (x.user_id)::uuid, 
        'authenticated', 
        'authenticated', 
        x.npsn || '@mail.com', 
        crypt(x.npsn, gen_salt('bf')), 
        now(), now(), now(), 
        json_build_object('provider', 'email', 'providers', json_build_array('email'))::jsonb, 
        '{}'::jsonb, 
        now(), now(), '', '', '', ''
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.users u WHERE u.email = x.npsn || '@mail.com');

    -- 3. Insert auth.identities
    INSERT INTO auth.identities (
        id, user_id, provider_id, identity_data, provider, last_sign_in_at, created_at, updated_at
    )
    SELECT 
        (x.user_id)::uuid, 
        (x.user_id)::uuid, 
        x.user_id, 
        json_build_object('sub', x.user_id, 'email', x.npsn || '@mail.com')::jsonb, 
        'email', 
        now(), now(), now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM auth.identities i WHERE i.id = (x.user_id)::uuid);

    -- 4. Insert public.profiles
    INSERT INTO public.profiles (id, role, school_id, created_at)
    SELECT 
        (x.user_id)::uuid, 
        'SCHOOL', 
        (x.school_id)::uuid, 
        now()
    FROM json_to_recordset(v_data) AS x(
        user_id text, school_id text, npsn text
    )
    WHERE NOT EXISTS (SELECT 1 FROM public.profiles p WHERE p.id = (x.user_id)::uuid);
END $$;
